mapper.select:
SELECT br.*, b.id as b_id, b.isbn as b_isbn, b.title as b_title, b.author as b_author, b.publisher as b_publisher, b.year as b_year, b.total as b_total, b.available as b_available, b.status as b_status, b.cover as b_cover, b.categoryId as b_categoryId, bi.id as bi_id, bi.barcode as bi_barcode, bi.callNumber as bi_callNumber, bi.location as bi_location, bi.status as bi_status, bi.price as bi_price, bi.bookId as bi_bookId, bi.itemTypeId as bi_itemTypeId, u.id as u_id, u.username as u_username, u.name as u_name, u.role as u_role, u.phone as u_phone, u.email as u_email, u.total_fines as u_total_fines, u.patronCategoryId as u_patronCategoryId, u.created_at as u_created_at, u.updated_at as u_updated_at FROM borrow_records br LEFT JOIN books b ON br.bookId = b.id LEFT JOIN book_items bi ON br.bookItemId = bi.id LEFT JOIN users u ON br.userId = u.id
AND br.status = #{status}
AND b.categoryId = #{categoryId}
AND (u.name LIKE CONCAT('%', #{search}, '%') OR u.username LIKE CONCAT('%', #{search}, '%') OR b.title LIKE CONCAT('%', #{search}, '%'))
ORDER BY br.borrow_date DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM borrow_records br
LEFT JOIN books b ON br.bookId = b.id


    AND br.status = #{status}


    AND b.categoryId = #{categoryId}


    AND (br.userId IN (SELECT id FROM users WHERE name LIKE CONCAT('%', #{search}, '%') OR username LIKE CONCAT('%', #{search}, '%'))
    OR br.bookId IN (SELECT id FROM books WHERE title LIKE CONCAT('%', #{search}, '%')))
